def f(n: int) -> int:
    """Return the n‑th prime (1‑based). Works for n up to at least 100."""
    if n < 1:
        raise ValueError("n must be a positive integer")
    # Upper bound for the 100th prime is 541 (known), add a safety margin.
    limit = 600
    sieve = [True] * (limit + 1)
    sieve[0] = sieve[1] = False
    primes = []
    for p in range(2, limit + 1):
        if sieve[p]:
            primes.append(p)
            if len(primes) == n:
                return p
            for multiple in range(p * p, limit + 1, p):
                sieve[multiple] = False
    # If the bound was insufficient (shouldn't happen for n ≤ 100), extend it.
    candidate = limit + 1
    while len(primes) < n:
        is_prime = True
        for prime in primes:
            if prime * prime > candidate:
                break
            if candidate % prime == 0:
                is_prime = False
                break
        if is_prime:
            primes.append(candidate)
        candidate += 1
    return primes[n - 1]
