def f(lst):
    # Boyer-Moore majority vote algorithm
    candidate = None
    count = 0
    for x in lst:
        if count == 0:
            candidate, count = x, 1
        elif x == candidate:
            count += 1
        else:
            count -= 1

    # Verify the candidate actually appears > len(lst)//2 times
    if candidate is not None and lst.count(candidate) > len(lst) // 2:
        return candidate
    return None
